'use client';

import React, { useMemo, useState } from 'react';
import AdminLayout from '../../../components/AdminLayout';

type UserStatus = 'ACTIVE' | 'INACTIVE' | 'PENDING' | 'ON_LEAVE';

type User = {
  id: string;
  name: string;
  email: string;
  phone: string;
  apartment: string;
  joinDate: string;
  status: UserStatus;
  rentStatus: 'PAID' | 'DUE' | 'OVERDUE';
  rentDueDate: string;
  maintenanceStatus: 'NONE' | 'DUE' | 'OVERDUE';
  maintenanceDueDate: string;
};

const usersSeed: User[] = [
  { id: 'USR-001', name: 'John Smith', email: 'john@email.com', phone: '+1-555-0101', apartment: 'A-301', joinDate: '2025-01-15', status: 'ACTIVE', rentStatus: 'PAID', rentDueDate: '2026-04-01', maintenanceStatus: 'NONE', maintenanceDueDate: '' },
  { id: 'USR-002', name: 'Sarah Johnson', email: 'sarah@email.com', phone: '+1-555-0102', apartment: 'A-302', joinDate: '2025-03-22', status: 'ACTIVE', rentStatus: 'DUE', rentDueDate: '2026-03-15', maintenanceStatus: 'DUE', maintenanceDueDate: '2026-03-20' },
  { id: 'USR-003', name: 'Mike Davis', email: 'mike@email.com', phone: '+1-555-0103', apartment: 'A-303', joinDate: '2024-10-01', status: 'INACTIVE', rentStatus: 'OVERDUE', rentDueDate: '2026-02-25', maintenanceStatus: 'OVERDUE', maintenanceDueDate: '2026-02-26' },
  { id: 'USR-004', name: 'Emma Clark', email: 'emma@email.com', phone: '+1-555-0104', apartment: 'B-102', joinDate: '2025-11-10', status: 'PENDING', rentStatus: 'DUE', rentDueDate: '2026-03-18', maintenanceStatus: 'NONE', maintenanceDueDate: '' },
  { id: 'USR-005', name: 'David Lee', email: 'david@email.com', phone: '+1-555-0105', apartment: 'C-210', joinDate: '2023-08-30', status: 'ON_LEAVE', rentStatus: 'PAID', rentDueDate: '2026-04-01', maintenanceStatus: 'NONE', maintenanceDueDate: '' },
  { id: 'USR-006', name: 'Nina Patel', email: 'nina@email.com', phone: '+1-555-0106', apartment: 'C-211', joinDate: '2025-12-09', status: 'ACTIVE', rentStatus: 'PAID', rentDueDate: '2026-04-01', maintenanceStatus: 'DUE', maintenanceDueDate: '2026-03-25' },
];

function statusClass(status: UserStatus) {
  if (status === 'ACTIVE') return 'bg-green-100 text-green-700';
  if (status === 'INACTIVE') return 'bg-gray-200 text-gray-700';
  if (status === 'PENDING') return 'bg-amber-100 text-amber-700';
  return 'bg-blue-100 text-blue-700';
}

function formatFinancial(status: User['rentStatus'], dueDate: string) {
  if (status === 'PAID') return 'Paid';
  if (status === 'OVERDUE') return 'OVERDUE';
  return `Due ${new Date(dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`;
}

export default function UsersPage() {
  const [query, setQuery] = useState('');
  const [category, setCategory] = useState<'ALL' | UserStatus>('ALL');
  const [sortBy, setSortBy] = useState<'NAME' | 'JOIN_DATE' | 'RENT_DUE' | 'MAINTENANCE_DUE'>('NAME');

  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [tab, setTab] = useState<'PROFILE' | 'BOOKINGS' | 'PAYMENTS' | 'MAINTENANCE'>('PROFILE');

  const [page, setPage] = useState(1);
  const perPage = 10;

  const filteredUsers = useMemo(() => {
    const cleaned = query.trim().toLowerCase();
    let list = usersSeed.filter((u) => {
      const searchMatch =
        !cleaned ||
        u.name.toLowerCase().includes(cleaned) ||
        u.id.toLowerCase().includes(cleaned) ||
        u.email.toLowerCase().includes(cleaned) ||
        u.phone.toLowerCase().includes(cleaned);
      const categoryMatch = category === 'ALL' || u.status === category;
      return searchMatch && categoryMatch;
    });

    list = [...list].sort((a, b) => {
      if (sortBy === 'NAME') return a.name.localeCompare(b.name);
      if (sortBy === 'JOIN_DATE') return b.joinDate.localeCompare(a.joinDate);
      if (sortBy === 'RENT_DUE') return a.rentDueDate.localeCompare(b.rentDueDate);
      return a.maintenanceDueDate.localeCompare(b.maintenanceDueDate);
    });

    return list;
  }, [query, category, sortBy]);

  const pageCount = Math.max(1, Math.ceil(filteredUsers.length / perPage));
  const pageUsers = filteredUsers.slice((page - 1) * perPage, page * perPage);

  return (
    <AdminLayout title="Users">
      <section className="space-y-5">
        <div className="rounded-xl border border-gray-200 bg-white p-4 shadow-sm">
          <div className="grid grid-cols-1 gap-3 md:grid-cols-4">
            <input
              value={query}
              onChange={(e) => {
                setQuery(e.target.value);
                setPage(1);
              }}
              placeholder="Search by name, user ID, email, phone..."
              className="md:col-span-2 rounded-lg border border-gray-300 px-3 py-2 text-sm"
            />
            <select value={category} onChange={(e) => setCategory(e.target.value as 'ALL' | UserStatus)} className="rounded-lg border border-gray-300 px-3 py-2 text-sm">
              <option value="ALL">All</option>
              <option value="ACTIVE">Active</option>
              <option value="INACTIVE">Inactive</option>
              <option value="PENDING">Pending</option>
              <option value="ON_LEAVE">On Leave</option>
            </select>
            <select value={sortBy} onChange={(e) => setSortBy(e.target.value as 'NAME' | 'JOIN_DATE' | 'RENT_DUE' | 'MAINTENANCE_DUE')} className="rounded-lg border border-gray-300 px-3 py-2 text-sm">
              <option value="NAME">Name (A-Z)</option>
              <option value="JOIN_DATE">Join Date</option>
              <option value="RENT_DUE">Rent Due</option>
              <option value="MAINTENANCE_DUE">Maintenance Due</option>
            </select>
          </div>
        </div>

        <div className="rounded-xl border border-gray-200 bg-white p-4 shadow-sm">
          {filteredUsers.length === 0 ? (
            <div className="py-12 text-center">
              <p className="text-lg font-semibold">No users found. Add a new resident.</p>
              <button className="mt-4 rounded-lg bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700">Add User</button>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full min-w-[1100px] text-left text-sm">
                <thead>
                  <tr className="border-b border-gray-200 text-gray-500">
                    <th className="py-2">User ID</th>
                    <th className="py-2">Name</th>
                    <th className="py-2">Email</th>
                    <th className="py-2">Phone</th>
                    <th className="py-2">Apt/Unit</th>
                    <th className="py-2">Rent Status</th>
                    <th className="py-2">Maintenance Due</th>
                    <th className="py-2">Status</th>
                    <th className="py-2">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {pageUsers.map((user) => (
                    <tr key={user.id} className="border-b border-gray-100 last:border-0 hover:bg-gray-50">
                      <td className="py-3 font-medium text-blue-600">{user.id}</td>
                      <td className="py-3">{user.name}</td>
                      <td className="py-3">{user.email}</td>
                      <td className="py-3">{user.phone}</td>
                      <td className="py-3">{user.apartment}</td>
                      <td className="py-3">{formatFinancial(user.rentStatus, user.rentDueDate)}</td>
                      <td className="py-3">{user.maintenanceStatus === 'NONE' ? 'None due' : formatFinancial(user.maintenanceStatus === 'OVERDUE' ? 'OVERDUE' : 'DUE', user.maintenanceDueDate)}</td>
                      <td className="py-3">
                        <span className={`rounded-full px-2.5 py-1 text-xs font-semibold ${statusClass(user.status)}`}>{user.status}</span>
                      </td>
                      <td className="py-3">
                        <div className="flex gap-2">
                          <button onClick={() => setSelectedUser(user)} className="rounded-md border border-blue-200 px-2 py-1 text-xs font-medium text-blue-700 hover:bg-blue-50">
                            View Profile
                          </button>
                          <button className="rounded-md border border-gray-300 px-2 py-1 text-xs font-medium hover:bg-gray-100">Send Message</button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          <div className="mt-4 flex items-center justify-between border-t border-gray-200 pt-4 text-sm">
            <p className="text-gray-600">Page {page} of {pageCount}</p>
            <div className="flex gap-2">
              <button onClick={() => setPage((p) => Math.max(1, p - 1))} disabled={page === 1} className="rounded-md border border-gray-300 px-3 py-1.5 disabled:opacity-50">
                Previous
              </button>
              <button onClick={() => setPage((p) => Math.min(pageCount, p + 1))} disabled={page === pageCount} className="rounded-md border border-gray-300 px-3 py-1.5 disabled:opacity-50">
                Next
              </button>
            </div>
          </div>
        </div>
      </section>

      {selectedUser ? (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4">
          <div className="w-full max-w-3xl rounded-xl bg-white p-5 shadow-xl">
            <div className="flex items-center justify-between gap-3">
              <div>
                <h3 className="text-lg font-semibold">{selectedUser.name}</h3>
                <p className="text-sm text-gray-500">{selectedUser.id}</p>
              </div>
              <button onClick={() => setSelectedUser(null)} className="rounded-md border border-gray-300 px-3 py-1 text-sm hover:bg-gray-100">Close</button>
            </div>

            <div className="mt-4 inline-flex rounded-lg border border-gray-200 p-1">
              {(['PROFILE', 'BOOKINGS', 'PAYMENTS', 'MAINTENANCE'] as const).map((item) => (
                <button
                  key={item}
                  onClick={() => setTab(item)}
                  className={[
                    'rounded-md px-3 py-1.5 text-sm',
                    tab === item ? 'bg-blue-600 text-white' : 'text-gray-600 hover:bg-gray-100',
                  ].join(' ')}
                >
                  {item}
                </button>
              ))}
            </div>

            <div className="mt-4 rounded-lg border border-gray-200 p-4 text-sm">
              {tab === 'PROFILE' ? (
                <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
                  <p><span className="font-medium">Name:</span> {selectedUser.name}</p>
                  <p><span className="font-medium">Email:</span> {selectedUser.email}</p>
                  <p><span className="font-medium">Phone:</span> {selectedUser.phone}</p>
                  <p><span className="font-medium">Apartment:</span> {selectedUser.apartment}</p>
                  <p><span className="font-medium">Join Date:</span> {selectedUser.joinDate}</p>
                  <p><span className="font-medium">Status:</span> {selectedUser.status}</p>
                </div>
              ) : null}

              {tab === 'BOOKINGS' ? (
                <ul className="space-y-2">
                  <li className="rounded-md border border-gray-200 p-2">BOOK-001 | Gym | 06:00-07:00 | CONFIRMED</li>
                  <li className="rounded-md border border-gray-200 p-2">BOOK-015 | Lounge | 18:00-19:00 | PENDING</li>
                </ul>
              ) : null}

              {tab === 'PAYMENTS' ? (
                <div className="space-y-2">
                  <p>Rent: {formatFinancial(selectedUser.rentStatus, selectedUser.rentDueDate)}</p>
                  <p>Maintenance: {selectedUser.maintenanceStatus === 'NONE' ? 'None due' : formatFinancial(selectedUser.maintenanceStatus === 'OVERDUE' ? 'OVERDUE' : 'DUE', selectedUser.maintenanceDueDate)}</p>
                  <p>Payment history: Last payment on Mar 1, 2026</p>
                </div>
              ) : null}

              {tab === 'MAINTENANCE' ? (
                <ul className="space-y-2">
                  <li className="rounded-md border border-gray-200 p-2">Water leakage in bathroom - In Progress</li>
                  <li className="rounded-md border border-gray-200 p-2">Air conditioning noise - Open</li>
                </ul>
              ) : null}
            </div>
          </div>
        </div>
      ) : null}
    </AdminLayout>
  );
}
